public int maxValueInStack(int[] nums, int k) {
    int n = nums.length;
    if (k >= n) return -1;

    int max_val = Integer.MIN_VALUE;
    for (int i = 0; i <= k; ++i) {
        max_val = Math.max(max_val, nums[i]);
    }
    return max_val;
}
```

